import React from 'react';
import { Button, Intro2 } from 'component';
import styles from './Header.module.scss';

const Header = (props) => {
  const {
    lang
  } = props
  return (
    <header className={styles.header}>
      <div style={{ display: 'flex', alignItems: 'center' }}><Intro2 lang={lang} /></div>
      <div><Button title={lang['button']} /></div>
    </header>
  );
};

export default Header;