import React from 'react';
import { LanguageText, MenuText } from 'component';
import styles from './Language.module.scss';

const Language = (props) => {
  const {
    changeLanguage,
    current,
    lang
  } = props
  return (
    <article className={styles.language}>
      <MenuText title={lang.language} id={"language"} />
      <LanguageText changeLanguage={changeLanguage} current={current} />
    </article>
  );
};

export default Language;