import React from 'react';
import styles from './Nav.module.scss';

const Nav = (props) => {
  const {
    lang
  } = props
  return (
    <nav className={styles.nav}>
      {/* <a href="#">home</a> */}
      <a href="#language">{lang['language']}</a>
      <a href="#project">{lang['project']}</a>
      <a href="#footer">{lang['contact']}</a>
    </nav>
  );
};

export default Nav;